mapper.update:
/* mapper.login.com.erns.coching.LoginDAO.updatePwdErrorCnt */
UPDATE T_MEMB_INF SET
PSWD_ERR_CNT   = PSWD_ERR_CNT +1

	AND MEMB_SEQ = #{value, jdbcType=INTEGER}

/* mapper.login.com.erns.coching.LoginDAO.updateResetPwdErrorCnt */
UPDATE T_MEMB_INF SET
PSWD_ERR_CNT   = 0

	AND MEMB_SEQ = #{seq, jdbcType=INTEGER}

/* mapper.login.com.erns.coching.LoginDAO.updateLoingInfo */
UPDATE T_MEMB_INF SET
RCT_ACS_DTTM = now()
, RCT_ACS_IP = #{lastAccessIp, jdbcType=VARCHAR}

	AND MEMB_SEQ = #{seq, jdbcType=INTEGER}
